const cmdInfo = $('Filter').item.json;

const response = $input.item.json || {};
const errorData = $input.item.error || response.error || null;
const errorMsg = errorData ? (errorData.message || String(errorData)) : null;

// Unwrap the .output from Flask response
const output = response.output || {};

let status = "MANUAL_REVIEW";
let evidence = "Check failed to execute properly.";

const isNoSuchEntity =
  errorMsg && (
    errorMsg.includes("NoSuchEntity") ||
    errorMsg.includes("not found") ||
    errorMsg.includes("NoSuchPublicAccessBlockConfiguration") ||
    errorMsg.includes("UnsupportedOperationException") ||
    errorMsg.includes("DisabledException") ||
    errorMsg.includes("ResourceNotFoundException") ||
    errorMsg.includes("AccessDeniedException") ||
    errorMsg.includes("InvalidAccessException") ||
    errorMsg.includes("SubscriptionRequiredException")  // ADD THIS
  );

// SCENARIO 1: Real System Crash
if (errorMsg && !isNoSuchEntity) {
  return {
    check_name: cmdInfo.check_name,
    resource_type: cmdInfo.resource_type,
    compliance_status: "MANUAL_REVIEW",
    evidence_summary: `SYSTEM ERROR: API execution failed. Human verification required.`,
    aws_account_id: $('Filter').item.json.aws_account_id, 
    raw_data: errorMsg
  };
}

// SCENARIO 2: Evaluate against CIS Benchmarks
try {
  switch (cmdInfo.check_name) {

    case "IAM_AUTH_CHECK":
      if (output.Arn) {
        status = "PASS";
        evidence = `Authentication successful. Role verified: ${output.Arn}`;
      }
      break;

    case "IAM_PASSWORD_POLICY":
      if (isNoSuchEntity) {
        status = "FAIL";
        evidence = "FAIL: No custom IAM password policy exists. Default AWS policy is too weak.";
      } else if (output.PasswordPolicy) {
        const pol = output.PasswordPolicy;
        const isStrong =
          pol.MinimumPasswordLength >= 14 &&
          pol.RequireNumbers &&
          pol.RequireSymbols;

        status = isStrong ? "PASS" : "FAIL";
        evidence = isStrong
          ? "IAM Password policy is strictly enforced."
          : "FAIL: Password policy exists but lacks strict requirements (Length < 14 or missing symbols).";
      }
      break;

    case "IAM_ACCOUNT_SUMMARY":
      const summary = output.SummaryMap;
      if (summary) {
        const rootMfa = summary.AccountMFAEnabled === 1;
        status = rootMfa ? "PASS" : "FAIL";
        evidence = rootMfa
          ? "Root account MFA is enabled."
          : "CRITICAL FAIL: Root account MFA is NOT enabled.";
      }
      break;

    case "IAM_USER_LIST":
      if (output.Users) {
        status = "PASS";
        evidence = `Verified active IAM user inventory. Found ${output.Users.length} users.`;
      }
      break;

    case "VPC_LIST":
      if (output.Vpcs) {
        status = "PASS";
        evidence = `Found ${output.Vpcs.length} VPC(s) in the region.`;
      }
      break;

    case "VPC_FLOW_LOGS":
      const logs = output.FlowLogs || [];
      status = logs.length > 0 ? "PASS" : "FAIL";
      evidence = logs.length > 0
        ? "VPC network traffic is being logged."
        : "FAIL: VPC Flow Logs are disabled. No network audit trail exists.";
      break;

    case "EC2_VOLUMES":
      const volumes = output.Volumes || [];
      if (volumes.length === 0) {
        status = "PASS";
        evidence = "No EC2 volumes found. Nothing to audit.";
      } else {
        const unencrypted = volumes.filter((v) => v.Encrypted === false);
        status = unencrypted.length === 0 ? "PASS" : "FAIL";
        evidence = unencrypted.length === 0
          ? "All EC2 volumes are encrypted at rest."
          : `FAIL: Found ${unencrypted.length} unencrypted volumes.`;
      }
      break;

    case "EC2_DEFAULT_ENCRYPTION":
      const encryptionEnabled = output.EbsEncryptionByDefault === true;
      status = encryptionEnabled ? "PASS" : "FAIL";
      evidence = encryptionEnabled
        ? "EBS encryption by default is enabled."
        : "FAIL: EBS encryption by default is DISABLED.";
      break;

    case "RDS_INSTANCES":
      const dbs = output.DBInstances || [];
      if (dbs.length === 0) {
        status = "PASS";
        evidence = "No active RDS instances found. Nothing to audit.";
      } else {
        const unencryptedDbs = dbs.filter((db) => db.StorageEncrypted === false);
        status = unencryptedDbs.length === 0 ? "PASS" : "FAIL";
        evidence = unencryptedDbs.length === 0
          ? "All RDS instances are encrypted."
          : `FAIL: Found ${unencryptedDbs.length} unencrypted RDS instances.`;
      }
      break;

    case "SECURITY_GROUPS":
      const sgs = output.SecurityGroups || [];
      let openPorts = [];

      sgs.forEach((sg) => {
        (sg.IpPermissions || []).forEach((perm) => {
          const isSsh = perm.FromPort <= 22 && perm.ToPort >= 22;
          const isRdp = perm.FromPort <= 3389 && perm.ToPort >= 3389;

          if (isSsh || isRdp) {
            const isWorldOpen = (perm.IpRanges || []).some(
              (r) => r.CidrIp === "0.0.0.0/0"
            );
            if (isWorldOpen) {
              openPorts.push(`${sg.GroupId}:${isSsh ? "SSH" : "RDP"}`);
            }
          }
        });
      });

      status = openPorts.length === 0 ? "PASS" : "FAIL";
      evidence = status === "PASS"
        ? "All security groups restrict SSH/RDP access to specific IPs."
        : `FAIL: Unrestricted SSH/RDP access found in Groups: ${openPorts.join(", ")}.`;
      break;

    case "S3_ENCRYPTION":
      const encRules = output.ServerSideEncryptionConfiguration?.Rules || [];
      status = encRules.length > 0 ? "PASS" : "FAIL";
      evidence = encRules.length > 0
        ? `S3 bucket '${cmdInfo.bucket_name}' has server-side encryption enabled.`
        : `FAIL: S3 bucket '${cmdInfo.bucket_name}' has NO encryption configured.`;
      break;

    case "S3_VERSIONING":
      const vStatus = output.Status;
      status = vStatus === "Enabled" ? "PASS" : "FAIL";
      evidence = vStatus === "Enabled"
        ? `S3 bucket '${cmdInfo.bucket_name}' versioning is enabled.`
        : `FAIL: S3 bucket '${cmdInfo.bucket_name}' versioning is DISABLED. Data loss risk.`;
      break;

    case "S3_LOGGING":
      const logEnabled = output.LoggingEnabled ? true : false;
      status = logEnabled ? "PASS" : "FAIL";
      evidence = logEnabled
        ? `S3 bucket '${cmdInfo.bucket_name}' access logging is enabled.`
        : `FAIL: S3 bucket '${cmdInfo.bucket_name}' has NO access logging. No audit trail.`;
      break;

    case "S3_PUBLIC_BLOCK":
      if (isNoSuchEntity) {
        status = "FAIL";
        evidence = `FAIL: No account-level S3 public access block configured. All buckets could be publicly exposed.`;
      } else {
        const pb = output.PublicAccessBlockConfiguration || {};
        const fullyBlocked =
          pb.BlockPublicAcls &&
          pb.IgnorePublicAcls &&
          pb.BlockPublicPolicy &&
          pb.RestrictPublicBuckets;

        status = fullyBlocked ? "PASS" : "FAIL";
        evidence = fullyBlocked
          ? `Account-level S3 public access block is fully enabled.`
          : `FAIL: Account-level S3 public access block is INCOMPLETE. Some public access settings are missing.`;
      }
      break;

    case "S3_ACL":
      const grants = output.Grants || [];
      const publicGrant = grants.find(
        (g) =>
          g.Grantee?.URI === "http://acs.amazonaws.com/groups/global/AllUsers" ||
          g.Grantee?.URI === "http://acs.amazonaws.com/groups/global/AuthenticatedUsers"
      );

      status = publicGrant ? "FAIL" : "PASS";
      evidence = publicGrant
        ? `FAIL: S3 bucket '${cmdInfo.bucket_name}' ACL grants PUBLIC access.`
        : `S3 bucket '${cmdInfo.bucket_name}' ACL is private. No public grants found.`;
      break;

    case "RDS_ENCRYPTION":
      const rdsEncrypted = output === true;
      status = rdsEncrypted ? "PASS" : "FAIL";
      evidence = rdsEncrypted
        ? `RDS instance '${cmdInfo.db_id}' storage is encrypted.`
        : `FAIL: RDS instance '${cmdInfo.db_id}' storage is NOT encrypted.`;
      break;

    case "RDS_PUBLIC_ACCESS":
      const rdsPublic = output === true;
      status = rdsPublic ? "FAIL" : "PASS";
      evidence = rdsPublic
        ? `FAIL: RDS instance '${cmdInfo.db_id}' is PUBLICLY ACCESSIBLE. Critical exposure risk.`
        : `RDS instance '${cmdInfo.db_id}' is not publicly accessible.`;
      break;

    case "RDS_BACKUP":
      const retention = typeof output === "number" ? output : 0;
      status = retention >= 7 ? "PASS" : "FAIL";
      evidence = retention >= 7
        ? `RDS instance '${cmdInfo.db_id}' backup retention is ${retention} days.`
        : `FAIL: RDS instance '${cmdInfo.db_id}' backup retention is only ${retention} days. Minimum 7 required.`;
      break;

    case "RDS_MULTI_AZ":
      const multiAz = output === true;
      status = multiAz ? "PASS" : "FAIL";
      evidence = multiAz
        ? `RDS instance '${cmdInfo.db_id}' has Multi-AZ enabled. High availability confirmed.`
        : `FAIL: RDS instance '${cmdInfo.db_id}' has NO Multi-AZ. Single point of failure.`;
      break;

    case "IAM_USER_MFA":
      const mfaDevices = output.MFADevices || [];
      status = mfaDevices.length > 0 ? "PASS" : "FAIL";
      evidence = mfaDevices.length > 0
        ? `IAM user '${cmdInfo.user_name}' has MFA enabled (${mfaDevices.length} device(s)).`
        : `FAIL: IAM user '${cmdInfo.user_name}' has NO MFA enabled. Account takeover risk.`;
      break;

    case "IAM_USER_ACCESS_KEYS":
      const keys = output.AccessKeyMetadata || [];
      const activeKeys = keys.filter(k => k.Status === "Active");
      const oldKeys = activeKeys.filter(k => {
        const created = new Date(k.CreateDate);
        const daysSince = (Date.now() - created) / (1000 * 60 * 60 * 24);
        return daysSince > 90;
      });

      if (activeKeys.length === 0) {
        status = "PASS";
        evidence = `IAM user '${cmdInfo.user_name}' has no active access keys.`;
      } else if (oldKeys.length > 0) {
        status = "FAIL";
        evidence = `FAIL: IAM user '${cmdInfo.user_name}' has ${oldKeys.length} access key(s) older than 90 days. Rotation required.`;
      } else {
        status = "PASS";
        evidence = `IAM user '${cmdInfo.user_name}' has ${activeKeys.length} active key(s), all rotated within 90 days.`;
      }
      break;

    case "IAM_USER_POLICIES":
      const attachedPolicies = output.AttachedPolicies || [];
      const hasAdminPolicy = attachedPolicies.some(p =>
        p.PolicyName === "AdministratorAccess" || p.PolicyArn?.includes("AdministratorAccess")
      );
      status = hasAdminPolicy ? "FAIL" : "PASS";
      evidence = hasAdminPolicy
        ? `FAIL: IAM user '${cmdInfo.user_name}' has AdministratorAccess policy directly attached. Violates least privilege.`
        : `IAM user '${cmdInfo.user_name}' has no admin policies directly attached (${attachedPolicies.length} policies).`;
      break;

    case "IAM_USER_INLINE":
      const inlinePolicies = output.PolicyNames || [];
      status = inlinePolicies.length === 0 ? "PASS" : "FAIL";
      evidence = inlinePolicies.length === 0
        ? `IAM user '${cmdInfo.user_name}' has no inline policies. Good practice.`
        : `FAIL: IAM user '${cmdInfo.user_name}' has ${inlinePolicies.length} inline policy(s): ${inlinePolicies.join(', ')}. Inline policies are hard to audit.`;
      break;

    case "IAM_USER_GROUPS":
      const groups = output.Groups || [];
      status = groups.length > 0 ? "PASS" : "FAIL";
      evidence = groups.length > 0
        ? `IAM user '${cmdInfo.user_name}' is assigned to ${groups.length} group(s): ${groups.map(g => g.GroupName).join(', ')}.`
        : `FAIL: IAM user '${cmdInfo.user_name}' is not in any IAM group. Permissions should be managed via groups.`;
      break;

    case "EC2_PUBLIC_IP":
      // output is either a string IP or null
      const hasPublicIp = output !== null && output !== "" && typeof output === "string";
      status = hasPublicIp ? "FAIL" : "PASS";
      evidence = hasPublicIp
        ? `FAIL: EC2 instance '${cmdInfo.instance_id}' has a PUBLIC IP (${output}). Direct internet exposure risk.`
        : `EC2 instance '${cmdInfo.instance_id}' has no public IP. Good.`;
      break;

    case "EC2_IMDSV2":
      // output is MetadataOptions object
      const httpTokens = output?.HttpTokens;
      status = httpTokens === "required" ? "PASS" : "FAIL";
      evidence = httpTokens === "required"
        ? `EC2 instance '${cmdInfo.instance_id}' enforces IMDSv2. SSRF attacks blocked.`
        : `FAIL: EC2 instance '${cmdInfo.instance_id}' allows IMDSv1. Vulnerable to SSRF credential theft.`;
      break;

    case "EC2_MONITORING":
      // output is Monitoring object { State: "enabled" | "disabled" }
      const monState = output?.State;
      status = monState === "enabled" ? "PASS" : "FAIL";
      evidence = monState === "enabled"
        ? `EC2 instance '${cmdInfo.instance_id}' has detailed monitoring enabled.`
        : `FAIL: EC2 instance '${cmdInfo.instance_id}' monitoring is DISABLED. No visibility into instance health.`;
      break;

    case "EC2_SSM_AGENT":
      // output is InstanceInformationList array
      const ssmList = output?.InstanceInformationList || [];
      const ssmOnline = ssmList.some(i => i.PingStatus === "Online");
      status = ssmOnline ? "PASS" : "FAIL";
      evidence = ssmOnline
        ? `EC2 instance '${cmdInfo.instance_id}' has SSM Agent running. Patch management available.`
        : `FAIL: EC2 instance '${cmdInfo.instance_id}' SSM Agent is OFFLINE or not installed. Cannot enforce patching.`;
      break;

    case "EC2_VOLUME_ENCRYPTED":
      // output is array of {ID, Enc} objects
      const instanceVolumes = Array.isArray(output) ? output : [];
      if (instanceVolumes.length === 0) {
        status = "PASS";
        evidence = `EC2 instance '${cmdInfo.instance_id}' has no attached volumes to audit.`;
      } else {
        const unencVols = instanceVolumes.filter(v => v.Enc === false);
        status = unencVols.length === 0 ? "PASS" : "FAIL";
        evidence = unencVols.length === 0
          ? `EC2 instance '${cmdInfo.instance_id}' all ${instanceVolumes.length} volume(s) are encrypted.`
          : `FAIL: EC2 instance '${cmdInfo.instance_id}' has ${unencVols.length} UNENCRYPTED volume(s): ${unencVols.map(v => v.ID).join(', ')}.`;
      }
      break;

    case "CT_LOGGING_ENABLED":
      const isLogging = output.IsLogging === true;
      status = isLogging ? "PASS" : "FAIL";
      evidence = isLogging
        ? `CloudTrail '${cmdInfo.trail_name}' is actively logging.`
        : `FAIL: CloudTrail '${cmdInfo.trail_name}' logging is STOPPED. No audit trail being recorded.`;
      break;

    case "CT_MULTI_REGION":
      // output is true/false boolean directly from query
      const isMultiRegion = output === true;
      status = isMultiRegion ? "PASS" : "FAIL";
      evidence = isMultiRegion
        ? `CloudTrail '${cmdInfo.trail_name}' covers ALL regions. Full account visibility.`
        : `FAIL: CloudTrail '${cmdInfo.trail_name}' is single-region only. Activity in other regions is NOT logged.`;
      break;

    case "CT_LOG_VALIDATION":
      // output is true/false boolean directly from query
      const validationEnabled = output === true;
      status = validationEnabled ? "PASS" : "FAIL";
      evidence = validationEnabled
        ? `CloudTrail '${cmdInfo.trail_name}' log file validation is enabled. Tamper detection active.`
        : `FAIL: CloudTrail '${cmdInfo.trail_name}' log validation is DISABLED. Logs could be tampered without detection.`;
      break;

    case "CT_KMS_ENCRYPTION":
      // output is the KMSKeyId string or null
      const hasKmsKey = output !== null && output !== "" && typeof output === "string";
      status = hasKmsKey ? "PASS" : "FAIL";
      evidence = hasKmsKey
        ? `CloudTrail '${cmdInfo.trail_name}' logs are encrypted with KMS key: ${output}.`
        : `FAIL: CloudTrail '${cmdInfo.trail_name}' logs are NOT encrypted with KMS. Stored in plaintext.`;
      break;

    case "CT_S3_BUCKET":
      // output is the S3BucketName string or null
      const hasBucket = output !== null && output !== "" && typeof output === "string";
      status = hasBucket ? "PASS" : "FAIL";
      evidence = hasBucket
        ? `CloudTrail '${cmdInfo.trail_name}' is delivering logs to S3 bucket: '${output}'.`
        : `FAIL: CloudTrail '${cmdInfo.trail_name}' has NO S3 bucket configured. Logs are not being stored.`;
      break;

    case "KMS_KEY_ROTATION":
      if (isNoSuchEntity) {
        status = "PASS";
        evidence = `KMS key '${cmdInfo.key_id}' is AWS-managed. Rotation is handled automatically by AWS.`;
      } else {
        const rotationEnabled = output.KeyRotationEnabled === true;
        status = rotationEnabled ? "PASS" : "FAIL";
        evidence = rotationEnabled
          ? `KMS key '${cmdInfo.key_id}' has automatic rotation enabled.`
          : `FAIL: KMS key '${cmdInfo.key_id}' does NOT have automatic rotation enabled. Stale key material risk.`;
      }
      break;

    case "KMS_KEY_POLICY":
      // Check if key policy allows * principal (anyone) — critical misconfiguration
      const policyStr = output.Policy || "{}";
      let policyJson = {};
      try { policyJson = JSON.parse(policyStr); } catch(e) { policyJson = {}; }
      const statements = policyJson.Statement || [];
      const hasWildcardPrincipal = statements.some(stmt => {
        const principal = stmt.Principal;
        return (
          principal === "*" ||
          principal?.AWS === "*" ||
          (Array.isArray(principal?.AWS) && principal.AWS.includes("*"))
        );
      });
      status = hasWildcardPrincipal ? "FAIL" : "PASS";
      evidence = hasWildcardPrincipal
        ? `FAIL: KMS key '${cmdInfo.key_id}' policy allows wildcard (*) principal. Any AWS entity can use this key.`
        : `KMS key '${cmdInfo.key_id}' policy is restricted. No wildcard principals found.`;
      break;

    case "KMS_KEY_METADATA":
      const keyMeta = output.KeyMetadata || {};
      const keyState = keyMeta.KeyState;
      const keyManager = keyMeta.KeyManager;
      const keyEnabled = keyState === "Enabled";
      // AWS managed keys are fine as-is, customer managed should be enabled
      if (keyManager === "AWS") {
        status = "PASS";
        evidence = `KMS key '${cmdInfo.key_id}' is AWS-managed. State: ${keyState}. Auto-managed by AWS.`;
      } else if (keyEnabled) {
        status = "PASS";
        evidence = `KMS key '${cmdInfo.key_id}' is customer-managed and ENABLED. State: ${keyState}.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: KMS key '${cmdInfo.key_id}' is customer-managed but state is '${keyState}'. Key is not operational.`;
      }
      break;

    case "LAMBDA_PUBLIC_POLICY":
      // If no policy exists AWS returns ResourceNotFoundException
      // which is caught by isNoSuchEntity — means no public access = PASS
      if (isNoSuchEntity) {
        status = "PASS";
        evidence = `Lambda function '${cmdInfo.function_name}' has no resource policy. Not publicly accessible.`;
      } else {
        const policyRaw = output.Policy || "{}";
        let lambdaPolicy = {};
        try { lambdaPolicy = JSON.parse(policyRaw); } catch(e) { lambdaPolicy = {}; }
        const lambdaStmts = lambdaPolicy.Statement || [];
        const isPublic = lambdaStmts.some(stmt => {
          const principal = stmt.Principal;
          return (
            stmt.Effect === "Allow" && (
              principal === "*" ||
              principal?.Service === "*" ||
              principal?.AWS === "*" ||
              (Array.isArray(principal?.AWS) && principal.AWS.includes("*"))
            )
          );
        });
        status = isPublic ? "FAIL" : "PASS";
        evidence = isPublic
          ? `FAIL: Lambda function '${cmdInfo.function_name}' has a PUBLIC resource policy. Anyone can invoke it.`
          : `Lambda function '${cmdInfo.function_name}' resource policy is restricted. No public access.`;
      }
      break;

    case "LAMBDA_ENV_SECRETS":
      // Check if env vars contain hardcoded secrets (key names are a giveaway)
      const envVars = output.Environment?.Variables || {};
      const secretKeywords = ["SECRET", "PASSWORD", "PASS", "KEY", "TOKEN", "CREDENTIAL", "API_KEY", "PRIVATE"];
      const suspiciousKeys = Object.keys(envVars).filter(k =>
        secretKeywords.some(keyword => k.toUpperCase().includes(keyword))
      );
      // Also check if KMS key is used for env encryption
      const hasKmsEncryption = output.KMSKeyArn ? true : false;
      if (suspiciousKeys.length === 0) {
        status = "PASS";
        evidence = `Lambda function '${cmdInfo.function_name}' has no suspicious environment variable names detected.`;
      } else if (suspiciousKeys.length > 0 && hasKmsEncryption) {
        status = "PASS";
        evidence = `Lambda function '${cmdInfo.function_name}' has sensitive env vars (${suspiciousKeys.join(', ')}) but they are KMS-encrypted.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: Lambda function '${cmdInfo.function_name}' has potentially hardcoded secrets in env vars: ${suspiciousKeys.join(', ')}. Use Secrets Manager instead.`;
      }
      break;

    case "LAMBDA_VPC_CONFIG":
      // output is VpcConfig object directly from query
      const vpcId = output?.VpcId;
      const hasVpc = vpcId !== null && vpcId !== "" && typeof vpcId === "string";
      status = hasVpc ? "PASS" : "FAIL";
      evidence = hasVpc
        ? `Lambda function '${cmdInfo.function_name}' is deployed inside VPC '${vpcId}'. Network isolated.`
        : `FAIL: Lambda function '${cmdInfo.function_name}' is NOT inside a VPC. Runs in public AWS network space.`;
      break;

    case "LAMBDA_RUNTIME":
      // output is the runtime string directly from query e.g. "nodejs18.x"
      const runtime = typeof output === "string" ? output : "";
      // Deprecated runtimes that should not be used
      const deprecatedRuntimes = [
        "nodejs",        // EOL
        "nodejs4.3",     // EOL
        "nodejs6.10",    // EOL
        "nodejs8.10",    // EOL
        "nodejs10.x",    // EOL
        "nodejs12.x",    // EOL
        "python2.7",     // EOL
        "python3.6",     // EOL
        "python3.7",     // EOL
        "dotnetcore1.0", // EOL
        "dotnetcore2.0", // EOL
        "dotnetcore2.1", // EOL
        "ruby2.5",       // EOL
        "java8",         // EOL
      ];
      const isDeprecated = deprecatedRuntimes.includes(runtime);
      status = isDeprecated ? "FAIL" : "PASS";
      evidence = isDeprecated
        ? `FAIL: Lambda function '${cmdInfo.function_name}' uses DEPRECATED runtime '${runtime}'. Security patches no longer available.`
        : `Lambda function '${cmdInfo.function_name}' uses runtime '${runtime}'. Currently supported.`;
      break;

    case "LB_ACCESS_LOGS":
      const lbAttrs = output.Attributes || [];
      const accessLogsEnabled = lbAttrs.find(a => a.Key === "access_logs.s3.enabled");
      const logsOn = accessLogsEnabled?.Value === "true";
      status = logsOn ? "PASS" : "FAIL";
      evidence = logsOn
        ? `Load balancer '${cmdInfo.lb_name}' has access logging enabled to S3.`
        : `FAIL: Load balancer '${cmdInfo.lb_name}' has NO access logging. Traffic is not being recorded.`;
      break;

    case "LB_HTTPS_LISTENER":
      const listeners = output.Listeners || [];
      if (listeners.length === 0) {
        status = "FAIL";
        evidence = `FAIL: Load balancer '${cmdInfo.lb_name}' has NO listeners configured.`;
      } else {
        const httpListeners = listeners.filter(l => l.Protocol === "HTTP");
        const httpsListeners = listeners.filter(l => l.Protocol === "HTTPS");
        // Check if any HTTP listener redirects to HTTPS
        const httpWithRedirect = httpListeners.filter(l =>
          (l.DefaultActions || []).some(a => a.Type === "redirect" && a.RedirectConfig?.Protocol === "HTTPS")
        );
        const allHttpSecure = httpListeners.length === 0 || httpWithRedirect.length === httpListeners.length;
        status = (httpsListeners.length > 0 && allHttpSecure) ? "PASS" : "FAIL";
        evidence = status === "PASS"
          ? `Load balancer '${cmdInfo.lb_name}' enforces HTTPS. HTTP redirects to HTTPS.`
          : `FAIL: Load balancer '${cmdInfo.lb_name}' has unprotected HTTP listeners without HTTPS redirect. Traffic is unencrypted.`;
      }
      break;

    case "LB_DELETION_PROTECTION":
      const delAttrs = output.Attributes || [];
      const delProtection = delAttrs.find(a => a.Key === "deletion_protection.enabled");
      const isProtected = delProtection?.Value === "true";
      status = isProtected ? "PASS" : "FAIL";
      evidence = isProtected
        ? `Load balancer '${cmdInfo.lb_name}' has deletion protection enabled.`
        : `FAIL: Load balancer '${cmdInfo.lb_name}' has NO deletion protection. Can be accidentally deleted.`;
      break;

    case "LB_SCHEME":
      // output is the scheme string directly — "internet-facing" or "internal"
      const scheme = typeof output === "string" ? output : "";
      status = scheme === "internal" ? "PASS" : "FAIL";
      evidence = scheme === "internal"
        ? `Load balancer '${cmdInfo.lb_name}' is INTERNAL. Not exposed to public internet.`
        : `FAIL: Load balancer '${cmdInfo.lb_name}' is INTERNET-FACING. Ensure this is intentional and properly secured.`;
      break;

    case "SQS_ENCRYPTION":
      const sqsAttrs = output.Attributes || {};
      const hasSqsKms = sqsAttrs.KmsMasterKeyId && sqsAttrs.KmsMasterKeyId !== "";
      const hasSqsSse = sqsAttrs.SqsManagedSseEnabled === "true";
      const sqsEncrypted = hasSqsKms || hasSqsSse;
      status = sqsEncrypted ? "PASS" : "FAIL";
      evidence = sqsEncrypted
        ? hasSqsKms
          ? `SQS queue '${cmdInfo.queue_name}' is encrypted with KMS key: ${sqsAttrs.KmsMasterKeyId}.`
          : `SQS queue '${cmdInfo.queue_name}' is encrypted with SSE-SQS managed encryption.`
        : `FAIL: SQS queue '${cmdInfo.queue_name}' has NO encryption. Messages stored in plaintext.`;
      break;

    case "SQS_PUBLIC_POLICY":
      const sqsPolicyAttrs = output.Attributes || {};
      const sqsPolicyRaw = sqsPolicyAttrs.Policy;
      if (!sqsPolicyRaw) {
        status = "PASS";
        evidence = `SQS queue '${cmdInfo.queue_name}' has no resource policy. Not publicly accessible.`;
      } else {
        let sqsPolicy = {};
        try { sqsPolicy = JSON.parse(sqsPolicyRaw); } catch(e) { sqsPolicy = {}; }
        const sqsStmts = sqsPolicy.Statement || [];
        const sqsIsPublic = sqsStmts.some(stmt => {
          const principal = stmt.Principal;
          return (
            stmt.Effect === "Allow" && (
              principal === "*" ||
              principal?.AWS === "*" ||
              (Array.isArray(principal?.AWS) && principal.AWS.includes("*"))
            )
          );
        });
        status = sqsIsPublic ? "FAIL" : "PASS";
        evidence = sqsIsPublic
          ? `FAIL: SQS queue '${cmdInfo.queue_name}' policy allows PUBLIC access (*). Anyone can send/receive messages.`
          : `SQS queue '${cmdInfo.queue_name}' policy is restricted. No public principals found.`;
      }
      break;

    case "SQS_DLQ_CONFIGURED":
      const sqsDlqAttrs = output.Attributes || {};
      const redrivePolicy = sqsDlqAttrs.RedrivePolicy;
      const hasDlq = redrivePolicy && redrivePolicy !== "";
      status = hasDlq ? "PASS" : "FAIL";
      evidence = hasDlq
        ? `SQS queue '${cmdInfo.queue_name}' has a Dead Letter Queue configured. Failed messages will be captured.`
        : `FAIL: SQS queue '${cmdInfo.queue_name}' has NO Dead Letter Queue. Failed messages will be silently lost.`;
      break;

    case "ROLE_TRUST_POLICY":
      // Check if trust policy allows * principal (anyone can assume this role)
      const trustStmts = output.Statement || [];
      const wildcardTrust = trustStmts.some(stmt => {
        const principal = stmt.Principal;
        return (
          stmt.Effect === "Allow" && (
            principal === "*" ||
            principal?.AWS === "*" ||
            (Array.isArray(principal?.AWS) && principal.AWS.includes("*"))
          )
        );
      });
      status = wildcardTrust ? "FAIL" : "PASS";
      evidence = wildcardTrust
        ? `FAIL: IAM role '${cmdInfo.role_name}' trust policy allows ANY principal (*) to assume it. Critical privilege escalation risk.`
        : `IAM role '${cmdInfo.role_name}' trust policy is restricted to specific principals.`;
      break;

    case "ROLE_ATTACHED_POLICIES":
      const roleAttachedPolicies = output.AttachedPolicies || [];
      const roleHasAdmin = roleAttachedPolicies.some(p =>
        p.PolicyName === "AdministratorAccess" ||
        p.PolicyArn?.includes("AdministratorAccess")
      );
      if (roleHasAdmin) {
        status = "FAIL";
        evidence = `FAIL: IAM role '${cmdInfo.role_name}' has AdministratorAccess attached. Full account access granted. Violates least privilege.`;
      } else if (roleAttachedPolicies.length === 0) {
        status = "PASS";
        evidence = `IAM role '${cmdInfo.role_name}' has no attached managed policies.`;
      } else {
        status = "PASS";
        evidence = `IAM role '${cmdInfo.role_name}' has ${roleAttachedPolicies.length} managed policy(s) attached. No admin access found.`;
      }
      break;

    case "ROLE_INLINE_POLICIES":
      const roleInlinePolicies = output.PolicyNames || [];
      status = roleInlinePolicies.length === 0 ? "PASS" : "FAIL";
      evidence = roleInlinePolicies.length === 0
        ? `IAM role '${cmdInfo.role_name}' has no inline policies. Good practice.`
        : `FAIL: IAM role '${cmdInfo.role_name}' has ${roleInlinePolicies.length} inline policy(s): ${roleInlinePolicies.join(', ')}. Inline policies bypass central access management.`;
      break;

    case "IAM_ROLES_LIST":
      const rolesList = output.Roles || [];
      status = "PASS";
      evidence = `IAM role inventory complete. Found ${rolesList.length} role(s) in account.`;
      break;

    case "IAM_POLICIES_CUSTOM":
      const customPolicies = output.Policies || [];
      if (customPolicies.length === 0) {
        status = "PASS";
        evidence = "No custom IAM policies found. Account uses AWS managed policies only.";
      } else {
        status = "PASS";
        evidence = `Found ${customPolicies.length} custom IAM policy(s). Ensure each follows least privilege.`;
      }
      break;

    case "IAM_GROUPS_LIST":
      const iamGroups = output.Groups || [];
      if (iamGroups.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No IAM groups exist. Users should be organized into groups for permission management.";
      } else {
        status = "PASS";
        evidence = `Found ${iamGroups.length} IAM group(s). Group-based permission management is in place.`;
      }
      break;

    case "IAM_SAML_PROVIDERS":
      const samlProviders = output.SAMLProviderList || [];
      if (samlProviders.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No SAML identity providers configured. Federated SSO is not enabled. Users rely on IAM passwords only.";
      } else {
        status = "PASS";
        evidence = `Found ${samlProviders.length} SAML provider(s). Federated identity/SSO is configured.`;
      }
      break;

    case "IAM_OIDC_PROVIDERS":
      const oidcProviders = output.OpenIDConnectProviderList || [];
      if (oidcProviders.length === 0) {
        status = "PASS";
        evidence = "No OIDC providers configured. Not required unless using EKS or federated workloads.";
      } else {
        status = "PASS";
        evidence = `Found ${oidcProviders.length} OIDC provider(s). Workload identity federation is configured.`;
      }
      break;

    case "IAM_VIRTUAL_MFA":
      const virtualMfaDevices = output.VirtualMFADevices || [];
      // Filter out root account MFA — check if non-root users have MFA assigned
      const assignedMfa = virtualMfaDevices.filter(d => d.SerialNumber && !d.SerialNumber.includes("root"));
      if (virtualMfaDevices.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No virtual MFA devices found in account. MFA is not being used.";
      } else {
        status = "PASS";
        evidence = `Found ${virtualMfaDevices.length} virtual MFA device(s). ${assignedMfa.length} assigned to non-root users.`;
      }
      break;

    case "IAM_ACCESS_ANALYZER":
      const analyzers = output.analyzers || [];
      const activeAnalyzers = analyzers.filter(a => a.status === "ACTIVE");
      if (activeAnalyzers.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No active IAM Access Analyzer found. External resource access is not being monitored.";
      } else {
        status = "PASS";
        evidence = `IAM Access Analyzer is ACTIVE. Found ${activeAnalyzers.length} active analyzer(s). External access is being monitored.`;
      }
      break;

    case "IAM_CREDENTIAL_REPORT":
      // generate-credential-report just triggers generation, returns State
      const reportState = output.State;
      if (reportState === "COMPLETE" || reportState === "STARTED") {
        status = "PASS";
        evidence = "IAM credential report generation triggered successfully. Report available for audit review.";
      } else {
        status = "MANUAL_REVIEW";
        evidence = `IAM credential report state: '${reportState}'. Verify report is accessible for auditors.`;
      }
      break;

    case "IAM_SUPPORT_ROLE":
      const supportPolicies = Array.isArray(output) ? output : [];
      if (supportPolicies.length === 0) {
        status = "FAIL";
        evidence = "FAIL: AWSSupportAccess policy not found. No designated support role exists. CIS Benchmark 1.17 violation.";
      } else {
        status = "PASS";
        evidence = `AWSSupportAccess policy exists. A designated support role is configured for incident management.`;
      }
      break;

    case "IAM_ROOT_ACCESS_KEYS":
      // output is the integer value directly from query (0 or 1)
      const rootKeysPresent = output === 1;
      status = rootKeysPresent ? "FAIL" : "PASS";
      evidence = rootKeysPresent
        ? "CRITICAL FAIL: Root account has ACTIVE ACCESS KEYS. Root keys must be deleted immediately. CIS Benchmark 1.4 violation."
        : "Root account has no access keys. Programmatic root access is disabled.";
      break;

    case "VPC_DEFAULT_SG":
      const defaultSgs = output.SecurityGroups || [];
      // CIS Rule: Default security group should have NO inbound or outbound rules
      const defaultSgsWithRules = defaultSgs.filter(sg =>
        (sg.IpPermissions && sg.IpPermissions.length > 0) ||
        (sg.IpPermissionsEgress && sg.IpPermissionsEgress.length > 0)
      );
      if (defaultSgs.length === 0) {
        status = "PASS";
        evidence = "No default security groups found.";
      } else if (defaultSgsWithRules.length === 0) {
        status = "PASS";
        evidence = `All ${defaultSgs.length} default security group(s) have no inbound/outbound rules. CIS compliant.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: ${defaultSgsWithRules.length} default security group(s) have active rules. Default SGs should have zero rules. CIS Benchmark 5.4 violation.`;
      }
      break;

    case "VPC_PEERING":
      const peeringConnections = output.VpcPeeringConnections || [];
      const activePeering = peeringConnections.filter(p => p.Status?.Code === "active");
      if (activePeering.length === 0) {
        status = "PASS";
        evidence = "No active VPC peering connections found. No cross-VPC network exposure.";
      } else {
        status = "MANUAL_REVIEW";
        evidence = `Found ${activePeering.length} active VPC peering connection(s). Verify each peering is intentional and least-privilege routing is enforced.`;
      }
      break;

    case "VPC_INTERNET_GATEWAYS":
      const igws = output.InternetGateways || [];
      const attachedIgws = igws.filter(igw =>
      igw.Attachments && igw.Attachments.some(a => a.State === "available")
       );
  if (attachedIgws.length === 0) {
    status = "PASS";
    evidence = "No internet gateways attached to any VPC. No direct internet routing.";
  } else {
    status = "FAIL";
    evidence = `FAIL: Found ${attachedIgws.length} internet gateway(s) attached to VPC(s). Ensure public subnets are intentional and all resources are properly secured behind security groups.`;
  }
  break;

    case "VPC_NACLS":
      const nacls = output.NetworkAcls || [];
      // CIS Rule: Ensure no NACL allows unrestricted inbound on port 22 or 3389
      let naclViolations = [];
      nacls.forEach(nacl => {
        (nacl.Entries || []).forEach(entry => {
          if (!entry.Egress && entry.RuleAction === "allow") {
            const portRange = entry.PortRange || {};
            const isSsh = portRange.From <= 22 && portRange.To >= 22;
            const isRdp = portRange.From <= 3389 && portRange.To >= 3389;
            const isAllPorts = entry.Protocol === "-1"; // all traffic
            const isWorldOpen =
              entry.CidrBlock === "0.0.0.0/0" ||
              entry.Ipv6CidrBlock === "::/0";
            if ((isSsh || isRdp || isAllPorts) && isWorldOpen) {
              naclViolations.push(`NACL:${nacl.NetworkAclId}`);
            }
          }
        });
      });
      status = naclViolations.length === 0 ? "PASS" : "FAIL";
      evidence = naclViolations.length === 0
        ? `All ${nacls.length} NACLs restrict unrestricted inbound access on sensitive ports.`
        : `FAIL: ${naclViolations.length} NACL(s) allow unrestricted inbound on SSH/RDP or all ports: ${[...new Set(naclViolations)].join(', ')}.`;
      break;

    case "VPC_SUBNETS":
      const subnets = output.Subnets || [];
      // Check for subnets that auto-assign public IPs — risk of accidental exposure
      const publicAutoAssign = subnets.filter(s => s.MapPublicIpOnLaunch === true);
      if (publicAutoAssign.length === 0) {
        status = "PASS";
        evidence = `All ${subnets.length} subnet(s) do NOT auto-assign public IPs. Instances launch privately by default.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: ${publicAutoAssign.length} subnet(s) auto-assign public IPs on launch. New instances get public IPs automatically: ${publicAutoAssign.map(s => s.SubnetId).join(', ')}.`;
      }
      break;

    case "VPC_ENDPOINTS":
      const vpcEndpoints = output.VpcEndpoints || [];
      const activeEndpoints = vpcEndpoints.filter(e => e.State === "available");
      if (activeEndpoints.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No VPC endpoints configured. AWS service traffic (S3, DynamoDB) routes over public internet instead of private AWS network.";
      } else {
        status = "PASS";
        evidence = `Found ${activeEndpoints.length} active VPC endpoint(s). AWS service traffic stays within private network.`;
      }
      break;

    case "NETWORK_INTERFACES":
      const enis = output.NetworkInterfaces || [];
      // Flag any ENIs with public IPs that are not attached
      const unattachedPublicEnis = enis.filter(e =>
        e.Status !== "in-use" && e.Association?.PublicIp
      );
      if (unattachedPublicEnis.length === 0) {
        status = "PASS";
        evidence = `Found ${enis.length} network interface(s). No unattached ENIs with public IPs detected.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: Found ${unattachedPublicEnis.length} unattached network interface(s) with public IPs. Orphaned ENIs waste cost and increase attack surface.`;
      }
      break;

    case "ELASTIC_IPS":
      const eips = output.Addresses || [];
      // Unassociated EIPs = wasted cost + potential security gap
      const unassociatedEips = eips.filter(e => !e.AssociationId);
      if (eips.length === 0) {
        status = "PASS";
        evidence = "No Elastic IPs allocated. No static public IP exposure.";
      } else if (unassociatedEips.length === 0) {
        status = "PASS";
        evidence = `Found ${eips.length} Elastic IP(s), all currently associated. No orphaned EIPs.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: Found ${unassociatedEips.length} unassociated Elastic IP(s) out of ${eips.length} total. Orphaned EIPs increase attack surface and incur unnecessary cost.`;
      }
      break;

    case "CT_TRAILS_LIST":
      const trailsList = output.trailList || [];
      if (trailsList.length === 0) {
        status = "FAIL";
        evidence = "CRITICAL FAIL: No CloudTrail trails found. Zero audit logging configured on this account. CIS Benchmark 3.1 violation.";
      } else {
        const multiRegionTrails = trailsList.filter(t => t.IsMultiRegionTrail === true);
        status = multiRegionTrails.length > 0 ? "PASS" : "FAIL";
        evidence = multiRegionTrails.length > 0
          ? `Found ${trailsList.length} trail(s), ${multiRegionTrails.length} covering all regions. Account-wide audit logging active.`
          : `FAIL: Found ${trailsList.length} trail(s) but NONE cover all regions. Activity in other regions is unlogged.`;
      }
      break;

    case "CT_EVENT_SELECTORS":
      // output is array of TrailARNs from query
      const trailArns = Array.isArray(output) ? output : [];
      if (trailArns.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No trails found to check event selectors. Management events are not being logged.";
      } else {
        status = "PASS";
        evidence = `Found ${trailArns.length} trail ARN(s). Event selector verification requires per-trail inspection. Trails exist for audit coverage.`;
      }
      break;

    case "CW_ALARMS_LIST":
      const cwAlarms = output.MetricAlarms || [];
      if (cwAlarms.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No CloudWatch alarms configured. No automated alerting exists for suspicious activity or resource thresholds.";
      } else {
        const alarmingAlarms = cwAlarms.filter(a => a.StateValue === "ALARM");
        status = "PASS";
        evidence = `Found ${cwAlarms.length} CloudWatch alarm(s). ${alarmingAlarms.length} currently in ALARM state. Automated monitoring is active.`;
      }
      break;

    case "CW_LOG_GROUPS":
      const logGroups = output.logGroups || [];
      if (logGroups.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No CloudWatch Log Groups found. Application and infrastructure logs are not being centralized.";
      } else {
        status = "PASS";
        evidence = `Found ${logGroups.length} CloudWatch Log Group(s). Centralized logging is configured.`;
      }
      break;

    case "CW_METRIC_FILTERS":
      const metricFilters = output.metricFilters || [];
      // CIS requires specific metric filters for root usage, unauthorized API calls etc.
      const cisRequiredPatterns = [
        "root",
        "ConsoleLogin",
        "AuthorizationFailure",
        "IAMPolicy",
        "CloudTrail",
        "S3BucketPolicy",
        "VPC",
      ];
      const foundPatterns = cisRequiredPatterns.filter(pattern =>
        metricFilters.some(f =>
          f.filterPattern && f.filterPattern.toLowerCase().includes(pattern.toLowerCase())
        )
      );
      if (metricFilters.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No CloudWatch metric filters configured. CIS Benchmark requires filters for root usage, auth failures, IAM changes, and more (CIS 3.1-3.14).";
      } else if (foundPatterns.length >= 4) {
        status = "PASS";
        evidence = `Found ${metricFilters.length} metric filter(s) covering key CIS patterns: ${foundPatterns.join(', ')}.`;
      } else {
        status = "FAIL";
        evidence = `FAIL: Found ${metricFilters.length} metric filter(s) but missing critical CIS patterns. Only covering: ${foundPatterns.join(', ') || 'none'}. Required: root, ConsoleLogin, AuthorizationFailure, IAMPolicy changes.`;
      }
      break;

    case "CW_LOG_RETENTION":
      // output is array of {name, retention} objects
      const logGroupsRetention = Array.isArray(output) ? output : [];
      if (logGroupsRetention.length === 0) {
        status = "PASS";
        evidence = "No log groups found to check retention on.";
      } else {
        // SOC2/ISO27001 require minimum 90 days, best practice is 365 days
        const noRetention = logGroupsRetention.filter(g => !g.retention || g.retention === null);
        const shortRetention = logGroupsRetention.filter(g => g.retention && g.retention < 90);
        if (noRetention.length > 0) {
          status = "FAIL";
          evidence = `FAIL: ${noRetention.length} log group(s) have NO retention policy set. Logs kept forever (cost risk) or deleted unpredictably: ${noRetention.map(g => g.name).slice(0,3).join(', ')}${noRetention.length > 3 ? '...' : ''}.`;
        } else if (shortRetention.length > 0) {
          status = "FAIL";
          evidence = `FAIL: ${shortRetention.length} log group(s) have retention under 90 days. SOC2/ISO27001 require minimum 90 days log retention.`;
        } else {
          status = "PASS";
          evidence = `All ${logGroupsRetention.length} log group(s) have retention policies of 90+ days. Compliant with SOC2/ISO27001.`;
        }
      }
      break;

    case "SNS_TOPICS_LIST":
      const snsTopics = output.Topics || [];
      if (snsTopics.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No SNS topics found. No notification infrastructure exists for security alerts or CloudWatch alarms.";
      } else {
        status = "PASS";
        evidence = `Found ${snsTopics.length} SNS topic(s). Notification infrastructure is in place for alerting.`;
      }
      break;

    case "SNS_SUBSCRIPTIONS":
      const snsSubs = output.Subscriptions || [];
      if (snsSubs.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No SNS subscriptions found. Even if topics exist, nobody is receiving alerts. Alarms are firing silently.";
      } else {
        const confirmedSubs = snsSubs.filter(s => s.SubscriptionArn !== "PendingConfirmation");
        status = confirmedSubs.length > 0 ? "PASS" : "FAIL";
        evidence = confirmedSubs.length > 0
          ? `Found ${confirmedSubs.length} confirmed SNS subscription(s). Alerts are being delivered to recipients.`
          : `FAIL: Found ${snsSubs.length} SNS subscription(s) but ALL are pending confirmation. Nobody is receiving alerts.`;
      }
      break;

    case "GUARDDUTY_DETECTORS":
      const detectorIds = output.DetectorIds || [];
      if (detectorIds.length === 0) {
        status = "FAIL";
        evidence = "CRITICAL FAIL: GuardDuty is NOT enabled. No threat detection running. Malicious activity, compromised credentials, and crypto-mining will go undetected. CIS Benchmark violation.";
      } else {
        status = "PASS";
        evidence = `GuardDuty is enabled with ${detectorIds.length} detector(s). Threat detection is active on this account.`;
      }
      break;

    case "GUARDDUTY_FINDINGS":
      // We reuse list-detectors — if detectors exist we check for active findings
      // High/Critical findings = FAIL, none or low = PASS
      const gdDetectors = output.DetectorIds || [];
      if (gdDetectors.length === 0) {
        status = "FAIL";
        evidence = "FAIL: GuardDuty not enabled. Cannot check for active threat findings.";
      } else {
        status = "PASS";
        evidence = `GuardDuty detector(s) active: ${gdDetectors.join(', ')}. Run findings check per-detector for active threat inventory.`;
      }
      break;

    case "SECURITYHUB_STATUS":
      // If SecurityHub not enabled AWS returns an error caught by isNoSuchEntity
      if (isNoSuchEntity) {
        status = "FAIL";
        evidence = "FAIL: AWS Security Hub is NOT enabled. Centralized security findings aggregation is missing. Required for SOC2 and CIS compliance monitoring.";
      } else {
        const hubArn = output.HubArn;
        const autoRemediation = output.AutoEnableControls;
        status = hubArn ? "PASS" : "FAIL";
        evidence = hubArn
          ? `AWS Security Hub is ENABLED. ARN: ${hubArn}. Auto-enable controls: ${autoRemediation ? 'Yes' : 'No'}.`
          : "FAIL: Security Hub response missing HubArn. Verify Security Hub configuration.";
      }
      break;

    case "SECURITYHUB_STANDARDS":
      // If SecurityHub not enabled this will also fail
      if (isNoSuchEntity) {
        status = "FAIL";
        evidence = "FAIL: Security Hub not enabled. No compliance standards are being monitored.";
      } else {
        const standards = output.StandardsSubscriptions || [];
        if (standards.length === 0) {
          status = "FAIL";
          evidence = "FAIL: Security Hub is enabled but NO compliance standards are subscribed. CIS AWS Foundations, PCI DSS, or FSBP should be enabled.";
        } else {
          const enabledStandards = standards.filter(s => s.StandardsStatus === "READY");
          const standardNames = enabledStandards.map(s => {
            if (s.StandardsArn.includes("cis-aws-foundations")) return "CIS AWS Foundations";
            if (s.StandardsArn.includes("pci-dss")) return "PCI DSS";
            if (s.StandardsArn.includes("aws-foundational")) return "AWS FSBP";
            if (s.StandardsArn.includes("nist")) return "NIST 800-53";
            return s.StandardsArn.split('/').pop();
          });
          status = enabledStandards.length > 0 ? "PASS" : "FAIL";
          evidence = enabledStandards.length > 0
            ? `Security Hub has ${enabledStandards.length} active standard(s): ${standardNames.join(', ')}.`
            : `FAIL: ${standards.length} standard(s) found but none are in READY state. Standards may still be enabling.`;
        }
      }
      break;

    case "INSPECTOR_STATUS":
      // Inspector2 list-coverage returns covered resources
      // If not enabled it throws an error caught by isNoSuchEntity
      if (isNoSuchEntity) {
        status = "FAIL";
        evidence = "FAIL: AWS Inspector is NOT enabled. Automated vulnerability scanning for EC2 and Lambda is not running. CVEs will go undetected.";
      } else {
        const coveredResources = output.coveredResources || [];
        if (coveredResources.length === 0) {
          status = "FAIL";
          evidence = "FAIL: AWS Inspector is enabled but no resources are being scanned. Verify EC2 and Lambda scanning is configured.";
        } else {
          status = "PASS";
          evidence = `AWS Inspector is scanning ${coveredResources.length} resource(s) for vulnerabilities.`;
        }
      }
      break;

    case "MACIE_STATUS":
      // If Macie not enabled AWS returns AccessDeniedException or similar
      if (isNoSuchEntity) {
        status = "FAIL";
        evidence = "FAIL: Amazon Macie is NOT enabled. Sensitive data (PII, credentials) in S3 buckets is not being discovered or monitored. Required for CAIQ/SIG data classification controls.";
      } else {
        const macieStatus = output.status;
        const findingFrequency = output.findingPublishingFrequency;
        if (macieStatus === "ENABLED") {
          status = "PASS";
          evidence = `Amazon Macie is ENABLED. S3 sensitive data discovery is active. Finding frequency: ${findingFrequency || 'default'}.`;
        } else if (macieStatus === "PAUSED") {
          status = "FAIL";
          evidence = "FAIL: Amazon Macie is PAUSED. Sensitive data monitoring is suspended. Re-enable to maintain data classification compliance.";
        } else {
          status = "FAIL";
          evidence = `FAIL: Amazon Macie status is '${macieStatus}'. Sensitive data in S3 is not being monitored.`;
        }
      }
      break;

    case "AWS_CONFIG_RECORDERS":
      const recorders = output.ConfigurationRecorders || [];
      if (recorders.length === 0) {
        status = "FAIL";
        evidence = "CRITICAL FAIL: AWS Config is NOT configured. No resource configuration history is being recorded. CIS Benchmark 3.5 violation. Required for SOC2, ISO27001, and CAIQ.";
      } else {
        const allResourceRecorder = recorders.find(r =>
          r.recordingGroup?.allSupported === true ||
          r.recordingGroup?.includeGlobalResourceTypes === true
        );
        status = allResourceRecorder ? "PASS" : "FAIL";
        evidence = allResourceRecorder
          ? `AWS Config recorder is configured and recording all supported resource types including global resources.`
          : `FAIL: AWS Config recorder exists but is NOT recording all resource types. Global resources like IAM may be missing from config history.`;
      }
      break;

    case "AWS_CONFIG_STATUS":
      const recorderStatuses = output.ConfigurationRecordersStatus || [];
      if (recorderStatuses.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No AWS Config recorder status found. Config may not be set up correctly.";
      } else {
        const recordingNow = recorderStatuses.filter(r => r.recording === true);
        const failedRecorders = recorderStatuses.filter(r =>
          r.lastStatus === "FAILURE" || r.lastStatus === "NOT_APPLICABLE"
        );
        if (recordingNow.length === 0) {
          status = "FAIL";
          evidence = `FAIL: AWS Config recorder exists but is NOT actively recording. Resource changes are not being tracked.`;
        } else if (failedRecorders.length > 0) {
          status = "FAIL";
          evidence = `FAIL: ${failedRecorders.length} AWS Config recorder(s) have FAILED status. Config history may have gaps.`;
        } else {
          status = "PASS";
          evidence = `AWS Config is actively recording. ${recordingNow.length} recorder(s) running with no failures.`;
        }
      }
      break;

    case "AWS_CONFIG_RULES":
      const configRules = output.ConfigRules || [];
      if (configRules.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No AWS Config rules defined. Automated compliance checks are not running. No continuous compliance monitoring in place.";
      } else {
        const managedRules = configRules.filter(r => r.Source?.Owner === "AWS");
        const customRules = configRules.filter(r => r.Source?.Owner === "CUSTOM_LAMBDA");
        status = "PASS";
        evidence = `Found ${configRules.length} Config rule(s): ${managedRules.length} AWS managed, ${customRules.length} custom. Continuous compliance monitoring active.`;
      }
      break;

    case "AWS_CONFIG_DELIVERY":
      const deliveryChannels = output.DeliveryChannels || [];
      if (deliveryChannels.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No AWS Config delivery channel configured. Even if recording is active, config snapshots and history are not being delivered to S3 or SNS.";
      } else {
        const withS3 = deliveryChannels.filter(d => d.s3BucketName && d.s3BucketName !== "");
        const withSns = deliveryChannels.filter(d => d.snsTopicARN && d.snsTopicARN !== "");
        status = withS3.length > 0 ? "PASS" : "FAIL";
        evidence = withS3.length > 0
          ? `AWS Config delivery channel configured. Delivering to S3: ${withS3[0].s3BucketName}. SNS notifications: ${withSns.length > 0 ? 'enabled' : 'not configured'}.`
          : `FAIL: Config delivery channel exists but has no S3 bucket configured. Config snapshots are not being stored.`;
      }
      break;

    case "AWS_CONFIG_COMPLIANCE":
      const complianceRules = output.ComplianceByConfigRules || [];
      if (complianceRules.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No Config compliance data found. Either no rules exist or compliance has not been evaluated yet.";
      } else {
        const nonCompliant = complianceRules.filter(r =>
          r.Compliance?.ComplianceType === "NON_COMPLIANT"
        );
        const compliant = complianceRules.filter(r =>
          r.Compliance?.ComplianceType === "COMPLIANT"
        );
        const notApplicable = complianceRules.filter(r =>
          r.Compliance?.ComplianceType === "NOT_APPLICABLE"
        );
        if (nonCompliant.length === 0) {
          status = "PASS";
          evidence = `All ${compliant.length} evaluated Config rule(s) are COMPLIANT. ${notApplicable.length} not applicable.`;
        } else {
          status = "FAIL";
          evidence = `FAIL: ${nonCompliant.length} Config rule(s) are NON-COMPLIANT out of ${complianceRules.length} total. Non-compliant rules: ${nonCompliant.map(r => r.ConfigRuleName).slice(0, 5).join(', ')}${nonCompliant.length > 5 ? '...' : ''}.`;
        }
      }
      break;

    case "SECRETS_MANAGER_LIST":
      const secretsList = output.SecretList || [];
      if (secretsList.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No secrets found in AWS Secrets Manager. Application credentials may be hardcoded in code or environment variables instead of using a secrets vault.";
      } else {
        status = "PASS";
        evidence = `Found ${secretsList.length} secret(s) in Secrets Manager. Centralized secrets vault is being used.`;
      }
      break;

    case "SECRETS_ROTATION":
      const secretsForRotation = output.SecretList || [];
      if (secretsForRotation.length === 0) {
        status = "PASS";
        evidence = "No secrets found in Secrets Manager. Nothing to check rotation on.";
      } else {
        const rotationEnabled = secretsForRotation.filter(s => s.RotationEnabled === true);
        const rotationDisabled = secretsForRotation.filter(s => !s.RotationEnabled);
        const neverRotated = secretsForRotation.filter(s => {
          if (!s.LastRotatedDate) return true;
          const daysSince = (Date.now() - new Date(s.LastRotatedDate)) / (1000 * 60 * 60 * 24);
          return daysSince > 90;
        });
        if (rotationDisabled.length === 0) {
          status = "PASS";
          evidence = `All ${secretsList.length} secret(s) have automatic rotation enabled.`;
        } else if (rotationDisabled.length === secretsForRotation.length) {
          status = "FAIL";
          evidence = `FAIL: ALL ${rotationDisabled.length} secret(s) have rotation DISABLED. Static credentials never expire. CIS/SOC2 violation.`;
        } else {
          status = "FAIL";
          evidence = `FAIL: ${rotationDisabled.length} of ${secretsForRotation.length} secret(s) have rotation disabled. ${neverRotated.length} have not been rotated in 90+ days.`;
        }
      }
      break;

    case "ACM_CERTIFICATES":
      const certs = output.CertificateSummaryList || [];
      if (certs.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No ACM certificates found. SSL/TLS termination may be using unmanaged certificates without automated renewal. Expiry risk.";
      } else {
        const issuedCerts = certs.filter(c => c.Status === "ISSUED");
        const pendingCerts = certs.filter(c => c.Status === "PENDING_VALIDATION");
        const failedCerts = certs.filter(c => c.Status === "FAILED");
        if (failedCerts.length > 0) {
          status = "FAIL";
          evidence = `FAIL: ${failedCerts.length} ACM certificate(s) in FAILED state. TLS may be broken for associated domains.`;
        } else {
          status = "PASS";
          evidence = `Found ${certs.length} ACM certificate(s): ${issuedCerts.length} issued, ${pendingCerts.length} pending validation. ACM manages auto-renewal.`;
        }
      }
      break;

    case "ACM_EXPIRY_CHECK":
      // output is array of {Arn, Domain, Status} from query
      const certDetails = Array.isArray(output) ? output : [];
      if (certDetails.length === 0) {
        status = "PASS";
        evidence = "No ACM certificates found to check expiry on.";
      } else {
        const expiredCerts = certDetails.filter(c => c.Status === "EXPIRED");
        const inactiveCerts = certDetails.filter(c =>
          c.Status !== "ISSUED" && c.Status !== "PENDING_VALIDATION"
        );
        if (expiredCerts.length > 0) {
          status = "FAIL";
          evidence = `CRITICAL FAIL: ${expiredCerts.length} ACM certificate(s) are EXPIRED: ${expiredCerts.map(c => c.Domain).join(', ')}. Services using these certs will show SSL errors.`;
        } else if (inactiveCerts.length > 0) {
          status = "FAIL";
          evidence = `FAIL: ${inactiveCerts.length} certificate(s) are not in active state: ${inactiveCerts.map(c => `${c.Domain}(${c.Status})`).join(', ')}.`;
        } else {
          status = "PASS";
          evidence = `All ${certDetails.length} ACM certificate(s) are in good standing. Domains covered: ${certDetails.map(c => c.Domain).slice(0, 5).join(', ')}${certDetails.length > 5 ? '...' : ''}.`;
        }
      }
      break;

    case "SSM_PARAMETERS":
      const ssmParams = output.Parameters || [];
      if (ssmParams.length === 0) {
        status = "FAIL";
        evidence = "FAIL: No SSM Parameter Store parameters found. Configuration values and secrets may be hardcoded in application code or unencrypted environment variables.";
      } else {
        // Check if sensitive params use SecureString type
        const secureParams = ssmParams.filter(p => p.Type === "SecureString");
        const plainParams = ssmParams.filter(p => p.Type === "String");
        const suspiciousPlain = plainParams.filter(p => {
          const name = p.Name.toUpperCase();
          return ["SECRET", "PASSWORD", "KEY", "TOKEN", "CREDENTIAL"].some(k => name.includes(k));
        });
        if (suspiciousPlain.length > 0) {
          status = "FAIL";
          evidence = `FAIL: Found ${suspiciousPlain.length} SSM parameter(s) with sensitive names stored as plaintext String instead of SecureString: ${suspiciousPlain.map(p => p.Name).join(', ')}.`;
        } else {
          status = "PASS";
          evidence = `Found ${ssmParams.length} SSM parameter(s): ${secureParams.length} encrypted SecureString, ${plainParams.length} plain String. No plaintext sensitive parameters detected.`;
        }
      }
      break;

    default:
      status = "MANUAL_REVIEW";
      evidence = `Logic for ${cmdInfo.check_name} is not yet implemented in the Switchboard.`;
  }
} catch (e) {
  status = "MANUAL_REVIEW";
  evidence = `PARSING ERROR: Failed to interpret AWS response. ${e.message}`;
}

return {
  check_name: cmdInfo.check_name,
  resource_type: cmdInfo.resource_type,
  compliance_status: status,
  evidence_summary: evidence,
  aws_account_id: $('Filter').item.json.aws_account_id, 
  raw_data: output
};
